        print( gridX );
    }




	distances = (float *)malloc(sizeof(float) * numRecords);
    d_locations = (LatLong *)malloc(sizeof(LatLong) * numRecords);
    d_distances = (float *)malloc(sizeof(float) * numRecords);

    if (!d_locations || !d_distances || !distances) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(1);
    }

    // Copy data to "device" (which is just host memory in OpenMP)
    for(i=0; i<numRecords; ++i) {
        d_locations[i] = locations[i];
    }





#ifdef  TIMING
  gettimeofday(&tv_kernel_start, NULL);
#endif

    euclid_openmp(d_locations, d_distances, numRecords, lat, lng);

#ifdef  TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif


    // Copy data back (already in host memory, but logically consistent)
    for(i=0; i<numRecords; ++i) {
        distances[i] = d_distances[i];
    }


    findLowest(records, distances, numRecords, resultsCount);


    if (!quiet)
    for(i=0;i<resultsCount;i++) {
